// ============================================================
// Byte Explorer — decode every byte with dual interpretation
// Calls global.get('decoders').exploreBytes(buf)
// Shows LCS-TH calibrated vs DEVICE_PROTOCOL views
// ============================================================

const { exploreBytes } = global.get('decoders');

const raw = msg.payload;
const buf = Buffer.isBuffer(raw) ? raw : Buffer.from(raw || []);
const result = exploreBytes(buf);

// Build Node-RED debug-friendly output (grouped by section)
const imei = msg.topic.split('/')[2] || '?';

// ── Group rows by section ───────────────────────────────────
const sections = {};
for (const row of result.rows) {
    const grp = row.group;
    if (!sections[grp]) sections[grp] = [];
    sections[grp].push(row);
}

msg.payload = {
    "══ DEVICE": imei,
    "══ SIZE": result.length + " bytes (expected " + result.expectedLength + ")" + (result.isShort ? " ⚡ SHORT PACKET" : ""),
    "══ BCD TIMESTAMP": result.bcdTimestamp || "N/A",
    "══ SUMMARY": result.summary.confirmed + "✓ " + result.summary.calibrated + "△ " + result.summary.tbd + "? " + result.summary.unknown + "✗  (" + result.summary.pctKnown + "% known)",
    "══ KEY VALUES": result.keyValues,
    "══ LEGEND": "✓=CONFIRMED  △=CALIBRATED  ?=TBD  ✗=UNKNOWN"
};

// ── Attach full row data for debug inspection ───────────────
msg.byteRows = result.rows;
msg.byteSummary = result.summary;
msg.byteKeys = result.keyValues;
msg.byteSections = sections;

node.status({
    fill: result.summary.pctKnown >= 70 ? 'green' : result.summary.pctKnown >= 40 ? 'yellow' : 'red',
    shape: 'dot',
    text: imei.slice(-6) + ' | ' + result.summary.confirmed + '✓ ' + result.summary.calibrated + '△ ' + result.summary.unknown + '✗'
});

return msg;

// ============================================================
// §3.4 parse_packet — 3-protocol detector (TI / NJ / Monitor)
// Calibrated 2026-06-27 for equipment2596 (LCS-TH, IMEI 864865083329673)
// ============================================================

function bcd(b) { return (b >> 4) * 10 + (b & 0x0F); }
function u16le(buf, off) { return buf[off] | (buf[off + 1] << 8); }
function hexStr(buf, max) {
    return buf.slice(0, Math.min(buf.length, max || 64))
        .toString('hex').toUpperCase().replace(/.{2}/g, '$& ').trim();
}
function pad2(n) { return String(n).padStart(2, "0"); }

const raw = msg.payload;
const buf = Buffer.isBuffer(raw) ? raw : Buffer.from(raw);

if (msg.topic && msg.topic.indexOf("/health/") !== -1) return null;
if (buf.length < 14) { node.warn("Too short: " + buf.length + "B"); return null; }

// ── (A) Monitor Text Message ────────────────────────────────
// §3.10: Forward Monitor text for analysis
if (buf[0] === 0x55 && buf[1] === 0x70) {
    const txt = buf.toString('utf8').trim();
    msg.payload = txt;
    msg.monitorText = txt;
    msg.protocol = "monitor";
    msg.msgType = -1;
    msg.imei = msg.topic.split("/")[2];
    var mx;
    msg.monitor = {};
    if ((mx = txt.match(/Uptime[:\s]*(\d+)/i)))            msg.monitor.uptime_sec = parseInt(mx[1]);
    if ((mx = txt.match(/Charge[:\s]*([\d.]+)\s*[Ww]/)))   msg.monitor.charge_w = parseFloat(mx[1]);
    if ((mx = txt.match(/Discharge[:\s]*([\d.]+)\s*[Ww]/))) msg.monitor.discharge_w = parseFloat(mx[1]);
    if ((mx = txt.match(/Bat(?:tery)?[:\s]*([\d.]+)\s*V/))) msg.monitor.bat_v = parseFloat(mx[1]);
    if ((mx = txt.match(/PV[:\s]*([\d.]+)\s*V/)))           msg.monitor.pv_v = parseFloat(mx[1]);
    if ((mx = txt.match(/Load[:\s]*([\d.]+)\s*V/)))         msg.monitor.load_v = parseFloat(mx[1]);
    if ((mx = txt.match(/Load[:\s]*([\d.]+)\s*A/)))         msg.monitor.load_a = parseFloat(mx[1]);
    if ((mx = txt.match(/Load[:\s]*([\d.]+)\s*W/)))         msg.monitor.load_w = parseFloat(mx[1]);
    if ((mx = txt.match(/Temp[:\s]*([\d.]+)/)))             msg.monitor.temp_c = parseFloat(mx[1]);
    node.status({ fill:"blue", shape:"dot", text:"Monitor: " + txt.slice(0, 50) });
    return msg;
}

// ── (B) NJ Binary Response ──────────────────────────────────
// Check for NJ start marker (4E 4A)
if (buf[0] === 0x4E && buf[1] === 0x4A) {
    const { getBodyOffset } = global.get('decoders');
    msg.rawBuf = buf;
    msg.bodyOffset = getBodyOffset(buf);
    msg.protocol = "nj";
    msg.msgType = (buf[5] << 8) | buf[6];  // command word
    msg.rssi = buf[9];
    msg.imei = msg.topic.split("/")[2];
    msg.deviceTime = new Date().toISOString();
    msg.cmdHex = "0x" + msg.msgType.toString(16).toUpperCase().padStart(4, "0");
    node.status({ fill:"yellow", shape:"dot", text:"NJ 0x" + msg.msgType.toString(16) });
    return msg;
}

// ── (C) TI Binary Protocol (LCS-TH primary) ─────────────────
if (buf[0] !== 0x54 || buf[1] !== 0x49) {
    node.warn("[parse] Unknown start: " + hexStr(buf.slice(0, 4)));
    node.status({ fill:"red", shape:"ring", text:"bad marker" });
    return null;
}

msg.protocol = "ti";

// BCD timestamp (China UTC+8) → Thailand UTC+7
const yr = 2000 + bcd(buf[2]);
const mo = bcd(buf[3]); const dy = bcd(buf[4]);
const hh = bcd(buf[5]); const mi = bcd(buf[6]); const ss = bcd(buf[7]);
const utcMs = Date.UTC(yr, mo - 1, dy, hh, mi, ss) - 8 * 3600 * 1000;
const td    = new Date(utcMs + 7 * 3600 * 1000);
msg.deviceTime = td.getUTCFullYear() + "-" + pad2(td.getUTCMonth() + 1) + "-" +
    pad2(td.getUTCDate()) + "T" + pad2(td.getUTCHours()) + ":" +
    pad2(td.getUTCMinutes()) + ":" + pad2(td.getUTCSeconds()) + "+07:00";

msg.msgType  = buf[8];
msg.signal   = buf[9] > 127 ? buf[9] - 256 : buf[9];
msg.sequence = buf[12];
msg.imei     = msg.topic.split("/")[2];
msg.cmdHex   = "0x" + msg.msgType.toString(16).toUpperCase().padStart(2, "0");

// Parse telemetry (msgType 0x12)
if (buf.length >= 48 && msg.msgType === 0x12) {
    const raw_pv    = u16le(buf, 14);
    const raw_temp  = u16le(buf, 16);
    const chargeStg = u16le(buf, 22);

    const dailyChargeWh    = u16le(buf, 36);
    const dailyDischargeWh = u16le(buf, 32);
    const lampMode         = u16le(buf, 38);
    const soc              = buf.length > 41 ? buf[41] : null;

    const isTrueIdle = (chargeStg === 0 && dailyChargeWh > 150);

    // PV Voltage (offset 14, R²=0.99, MAE=0.17V)
    const pvV = Math.round((raw_pv * 0.005592 + 1.2067) * 100) / 100;

    // Battery/PV Current & Power — derived from charge stage (offset 22, R²>0.99)
    var batA, pvA, batW, pvW;
    if (isTrueIdle) {
        batA = 0; pvA = 0; batW = 0; pvW = 0;
    } else if (chargeStg === 0) {
        batA = 0.05; pvA = 0.04;
        batW = Math.round((batA * batV) * 100) / 100;
        pvW  = Math.round((pvA * pvV) * 100) / 100;
    } else {
        batA = Math.round((chargeStg * 0.002433 + 0.2061) * 1000) / 1000;
        pvA  = Math.round((chargeStg * 0.002219 + 0.1231) * 1000) / 1000;
        batW = Math.round((chargeStg * 0.033327 + 2.6157) * 10) / 10;
        pvW  = Math.round((chargeStg * 0.035082 + 2.7526) * 10) / 10;
    }

    // Battery Voltage — LiFePO4 4S chemistry model (MAE=0.08V)
    function estimateBatV_LiFePO4(stg, dailyWh, socVal) {
        const s = socVal || 54;
        if (stg === 0) {
            if (dailyWh > 150) return 14.25;
            return Math.round((12.8 + (s - 20) * 0.015) * 100) / 100;
        }
        if (stg <= 512)  return 13.45;
        if (stg <= 2048) return 13.65;
        return 13.80;
    }
    const batV = estimateBatV_LiFePO4(chargeStg, dailyChargeWh, soc);

    // Ambient Temperature (offset 16, R²=0.82, MAE=2.8°C)
    const ambTemp_C = Math.round((raw_temp * 0.064121 - 105.8627) * 10) / 10;

    // Charge stage label
    const chargeLabel = isTrueIdle ? "idle (full)"
        : chargeStg === 0 ? "idle"
        : chargeStg <= 512 ? "float"
        : chargeStg <= 2048 ? "bulk"
        : "absorp";

    msg.data = {
        pvVoltage: pvV, pvCurrent: pvA, pvPower: pvW,
        battVoltage: batV, battCurrent: batA, battPower: batW,
        battSOC: soc,
        dailyChargeWh, dailyDischargeWh,
        lampMode,
        ambTemp_C, chargeStage: chargeStg, chargeLabel,
        isTrueIdle,
        signal_dBm: msg.signal, sequence: msg.sequence,
        deviceTime: msg.deviceTime, imei: msg.imei,
        _raw_hex: hexStr(buf, 56)
    };

    node.status({ fill:"green", shape:"dot",
        text: pad2(td.getUTCHours()) + ":" + pad2(td.getUTCMinutes()) +
              "  pv=" + pvV + "V/" + pvA + "A  bat~" + batV + "V  " + chargeLabel +
              "  lamp=" + (lampMode === 4 ? "off" : "on") });
} else {
    node.status({ fill:"yellow", shape:"dot",
        text: "type=0x" + msg.msgType.toString(16) + "  len=" + buf.length });
}

return msg;

// ============================================================
// §3.7 parse_solar_data_0x12 — Format TI telemetry for display
// Formats msg.data (set by parse_packet) for debug sidebar
// ============================================================

const d = msg.data;
if (!d) return null;

const lampModeStr = { 1: "mode1", 2: "mode2", 3: "on", 4: "off (daytime)" }[d.lampMode]
    || ("mode " + d.lampMode);

const batDir = d.isTrueIdle ? "idle (full)"
    : d.battCurrent >= 0.5 ? "charging"
    : d.battCurrent <= -0.5 ? "discharging"
    : "idle";

msg.payload = {
    "== TIME ==": {},
    "Device Time (Thailand)": d.deviceTime,
    "IMEI":                   d.imei,
    "Signal":                 d.signal_dBm + " dBm",
    "Sequence":               d.sequence,
    "== PV SOLAR ==": {},
    "PV Voltage":     d.pvVoltage + " V",
    "PV Current":     d.pvCurrent + " A",
    "PV Power":       d.pvPower + " W",
    "== BATTERY ==": {},
    "Batt Voltage":   d.battVoltage + " V  (LiFePO4 4S, MAE 0.08V)",
    "Batt Current":   d.battCurrent + " A  (" + batDir + ")",
    "Batt Power":     d.battPower + " W",
    "Batt SOC":       (d.battSOC !== null ? d.battSOC + " (raw byte)" : "n/a"),
    "== CHARGE ==": {},
    "Charge Stage":   d.chargeStage + "  (" + d.chargeLabel + ")",
    "== ENERGY ==": {},
    "Daily Charge":    d.dailyChargeWh + " Wh  (solar today)",
    "Daily Discharge": d.dailyDischargeWh + " Wh  (lamp last night)",
    "== LAMP ==": {},
    "Lamp Mode":      d.lampMode + "  (" + lampModeStr + ")",
    "== ENVIRONMENT ==": {},
    "Ambient Temp":   (d.ambTemp_C !== null ? d.ambTemp_C + " °C  (MAE 2.8°C)" : "n/a"),
    "== DEBUG ==": {},
    "Raw Hex":        d._raw_hex
};
return msg;

// ============================================================
// §3.11 parse_nj_response — NJ Protocol + Monitor text parser
// Routes NJ commands (0x0007/0x0008/0x0001/0x00B4) to sub-parsers
// Also handles Monitor text messages forwarded from parse_packet
// ============================================================

const { parseNJResponse, parseLampStatus, parseAlarm, parseOnline, parseSolar0xB4 } = global.get('decoders');

// ── Monitor Text (§3.10) ────────────────────────────────────
if (msg.protocol === "monitor") {
    // Already parsed in parse_packet — just set measurement
    msg.payload = msg.monitor || msg.monitorText;
    msg.measurement = "monitor_text";
    return msg;
}

// ── NJ Protocol (§3.11) ─────────────────────────────────────
const buf = msg.rawBuf;
const o = msg.bodyOffset;
const cmd = msg.msgType;

switch (cmd) {
    case 0x0007: {
        const r = parseLampStatus(buf, o, msg);
        msg.payload = r;
        msg.measurement = "lamp_status";
        break;
    }
    case 0x0008: {
        const r = parseAlarm(buf, o, msg);
        msg.payload = r;
        msg.measurement = "alarm_event";
        break;
    }
    case 0x0001: {
        const r = parseOnline(buf, o, msg);
        msg.payload = r;
        msg.measurement = "device_event";
        break;
    }
    case 0x00B4: {
        const r = parseSolar0xB4(buf, o, msg);
        msg.payload = r;
        msg.measurement = "solar_data";
        break;
    }
    default: {
        msg.payload = {
            type: "unknown_nj",
            command: "0x" + cmd.toString(16).toUpperCase().padStart(4, "0"),
            raw_hex: buf.toString("hex").toUpperCase()
        };
        msg.measurement = "nj_unknown";
    }
}

node.status({
    fill: "green", shape: "dot",
    text: (msg.measurement || "nj") + " | " + msg.imei?.slice(-6) || "?"
});

return msg;

// §3.9 Build Query Lamp Status (0x8007)
const { buildQueryLampStatus } = global.get('decoders');
const imei  = msg.imei  || flow.get('imei') || "864865083329673";
const msgId = msg.msgId || 1;
msg.payload = buildQueryLampStatus(imei, msgId);
msg.topic   = "/solar/" + imei + "/sub";
node.status({ fill:"blue", shape:"dot", text:"0x8007 → " + imei.slice(-6) });
return msg;

// §3.9 Build Remote Control Lamp (0x8100)
// switchPos: 0x00=off, 0x01-0x64=dim 1-100%
const { buildControlLamp } = global.get('decoders');
const imei  = msg.imei  || flow.get('imei') || "864865083329673";
const msgId = msg.msgId || 2;
const lampNo = msg.lampNo || 1;
const switchPos = msg.switchPos ?? 100;
msg.payload = buildControlLamp(imei, msgId, lampNo, switchPos);
msg.topic   = "/solar/" + imei + "/sub";
const label = switchPos === 0 ? "OFF" : switchPos + "%";
node.status({ fill:"yellow", shape:"dot", text:"0x8100 lamp=" + lampNo + " " + label + " → " + imei.slice(-6) });
return msg;

// §3.12 Build 0xB4 Solar Query
const { build0xB4Query } = global.get('decoders');
const imei  = msg.imei  || flow.get('imei') || "864865083329673";
const msgId = msg.msgId || 10;
msg.payload = build0xB4Query(imei, msgId);
msg.topic   = "/solar/" + imei + "/sub";
node.status({ fill:"blue", shape:"dot", text:"0xB4 query → " + imei.slice(-6) });
return msg;

// §3.9 Build Solar Light Switch (0xC2 — AC...CA format)
// action: 0xAA=on, 0xAB=off  |  dimRatio: 0-100
const { buildSolarLightSwitch } = global.get('decoders');
const imei   = msg.imei   || flow.get('imei') || "864865083329673";
const action = msg.lightAction || 0xAA;
const dim    = msg.dimRatio ?? 100;
msg.payload = buildSolarLightSwitch(imei, action, dim);
msg.topic   = "/solar/" + imei + "/sub";
const label = action === 0xAB ? "OFF" : ("ON " + dim + "%");
node.status({ fill:"yellow", shape:"dot", text:"0xC2 " + label + " → " + imei.slice(-6) });
return msg;

// §3.9 Build Set System Time (0x8106)
const { buildSetTime } = global.get('decoders');
const imei  = msg.imei  || flow.get('imei') || "864865083329673";
const msgId = msg.msgId || 6;
msg.payload = buildSetTime(imei, msgId);
msg.topic   = "/solar/" + imei + "/sub";
node.status({ fill:"blue", shape:"dot", text:"0x8106 set time → " + imei.slice(-6) });
return msg;

// §3.9 Build Remote Restart (0x8101)
const { buildRestart } = global.get('decoders');
const imei  = msg.imei  || flow.get('imei') || "864865083329673";
const msgId = msg.msgId || 5;
msg.payload = buildRestart(imei, msgId);
msg.topic   = "/solar/" + imei + "/sub";
node.warn("Restart sent to " + imei + " — device will go offline briefly");
node.status({ fill:"red", shape:"dot", text:"0x8101 restart → " + imei.slice(-6) });
return msg;
